import React, { useState, useEffect } from 'react';
import axios from 'axios';

const Home = () => {
  const [blogs, setBlogs] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchBlogs = async () => {
      try {
        const response = await axios.get('http://localhost:5003/api/blogs');
        setBlogs(response.data);
      } catch (error) {
        console.error('Error:', error);
      } finally {
        setLoading(false);
      }
    };
    fetchBlogs();
  }, []);

  return (
    <div style={{ maxWidth: '1200px', margin: '0 auto', padding: '20px' }}>
      {/* Navigation Bar */}
      <div style={{ 
        display: 'flex', 
        justifyContent: 'space-between', 
        alignItems: 'center', 
        marginBottom: '40px', 
        padding: '15px 0', 
        borderBottom: '2px solid #e0e0e0'
      }}>
        <h1 style={{ color: '#667eea', margin: 0, fontSize: '28px' }}>Blog Era</h1>
        <div style={{ display: 'flex', gap: '15px' }}>
          <a href="/" style={{ textDecoration: 'none', color: '#333', padding: '8px 16px' }}>Home</a>
          <a href="/login" style={{ textDecoration: 'none', backgroundColor: '#667eea', color: 'white', padding: '8px 20px', borderRadius: '5px' }}>Login</a>
          <a href="/register" style={{ textDecoration: 'none', backgroundColor: '#28a745', color: 'white', padding: '8px 20px', borderRadius: '5px' }}>Register</a>
        </div>
      </div>

      <div style={{ textAlign: 'center', marginBottom: '40px' }}>
        <h1 style={{ fontSize: '48px', marginBottom: '20px', color: '#667eea' }}>Welcome to Blog Era</h1>
        <p style={{ fontSize: '18px', color: '#666' }}>Discover amazing stories from talented writers</p>
      </div>

      <h2 style={{ marginBottom: '20px' }}>All Blog Posts</h2>
      
      {loading ? (
        <p>Loading blogs...</p>
      ) : blogs.length === 0 ? (
        <div style={{ textAlign: 'center', padding: '50px', background: '#f8f9fa', borderRadius: '10px' }}>
          <p>No blogs found. Create your first blog post!</p>
          <button onClick={() => window.location.reload()} style={{ padding: '10px 20px', background: '#667eea', color: 'white', border: 'none', borderRadius: '5px', cursor: 'pointer' }}>Refresh</button>
        </div>
      ) : (
        blogs.map((blog) => (
          <div key={blog._id} style={{ background: '#f8f9fa', padding: '20px', margin: '15px 0', borderRadius: '10px' }}>
            <h3 style={{ marginBottom: '10px' }}>{blog.title}</h3>
            <p style={{ color: '#666' }}>{blog.content?.substring(0, 150)}...</p>
            <a href={`/blog/${blog._id}`} style={{ color: '#667eea', textDecoration: 'none' }}>Read More →</a>
          </div>
        ))
      )}
    </div>
  );
};

export default Home;
